--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(200) NOT NULL,
  `sku` varchar(50) NOT NULL,
  `category_id` int(10) unsigned DEFAULT NULL,
  `unit` varchar(20) NOT NULL DEFAULT 'Cái',
  `price` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Giá bán lẻ',
  `cost_price` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Giá vốn',
  `stock_qty` decimal(10,3) NOT NULL DEFAULT 0.000 COMMENT 'Tổng tồn kho',
  `available_stock` decimal(10,3) NOT NULL DEFAULT 0.000 COMMENT 'Có thể bán',
  `reserved_stock` decimal(10,3) NOT NULL DEFAULT 0.000 COMMENT 'Tạm giữ',
  `low_stock_threshold` decimal(10,3) NOT NULL DEFAULT 10.000 COMMENT 'Cảnh báo hết hàng',
  `weight` decimal(8,2) DEFAULT NULL COMMENT 'gram',
  `length` decimal(8,2) DEFAULT NULL COMMENT 'cm',
  `width` decimal(8,2) DEFAULT NULL COMMENT 'cm',
  `height` decimal(8,2) DEFAULT NULL COMMENT 'cm',
  `description` text DEFAULT NULL,
  `images` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Array of image URLs' CHECK (json_valid(`images`)),
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`),
  KEY `idx_products_sku` (`sku`),
  KEY `idx_products_category` (`category_id`),
  KEY `idx_products_is_active` (`is_active`),
  KEY `idx_products_stock` (`stock_qty`),
  CONSTRAINT `fk_products_category` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=122 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

